/**
 * Opens a view that allows the user to upgrade to MPC v3 wallets.
 *
 */
const useUpgradeToDynamicWaasFlow = () => {
    const { setShowAuthFlow } = useInternalDynamicContext();
    const { pushView } = useViewContext();
    const promptUpgradeToDynamicWaasFlow = useCallback(() => {
        // Show the auth flow modal
        setShowAuthFlow(true, {
            ignoreIfIsEmbeddedWidget: false,
            performMultiWalletChecks: false,
        });
        // Navigate to the WaaS upgrade view
        pushView('waas-upgrade-view');
    }, [setShowAuthFlow, pushView]);
    return { promptUpgradeToDynamicWaasFlow };
};

export { useUpgradeToDynamicWaasFlow };
